form:Form.form:Scripts:
		var fecha;

function onload()
{   
	/*if(Ctrl('main').GetMode()=='SHOW-MASIVA')
	{
		alert("entra"); 
	} */

	//Seteo a fecha de adelanto en HOY si esta no esta cargada
	if(Ctrl('f_adelanto').GetXValue()=='')
	{
	Ctrl('f_adelanto').SetXValue(datetime2str(Now()));
	}

	//Seteo el monto en 0 en caso de que esté cargado  
	if(Ctrl("n_monto_adel").GetXValue() == "")
	{
		Ctrl("n_monto_adel").SetXValue("0");
	} 
	if(Ctrl('main').GetMode()=='NEW')
	{  
	  //Setear el valor del Nro de Adelanto en construcción
	  Ctrl("nro_adelanto").SetXValue("En construcción");
	  Ctrl("c_usr_crea").SetXValue(GetProxy().UserName());	

		//Si es la primera vez que abro la pantalla, seteo el parametro
		if(Ctrl('primer_new').GetXValue()=='1')
		{
				var nSQL = GetProxy().SQLService();
				//Setea el valor por defecto del parametro si este esta cargado	
				var tipoAdelanto = nSQL.GetOBJ(Ctrl("main").getResource("SetearTipoAdelanto"), "<DATA />");

				//Si no es 0, encontro el parametro y lo setea al supercombo	
				if(tipoAdelanto.valor!="0")
				{
			    Ctrl('oi_tipo_adelanto').SetXValue(tipoAdelanto.valor);
				} 


				//Setea el valor por defecto del parametro criticidad de fondos si este esta cargado
				var criticidadFondo = nSQL.GetOBJ(Ctrl('main').getResource("SetearCriticidadFondo"), "<DATA />");

				//Si no es 0, encontro el parametro y lo setea al supercombo	
				if(criticidadFondo.valor!="0")
				{
			    Ctrl('n_criticidad').SetXValue(criticidadFondo.valor);
				} 
		 }
	} 

	if(Ctrl('main').GetMode()=='SHOW' || Ctrl('main').GetMode()=='SHOW-MASIVA')
	{
		var oi_adelanto = Ctrl('id').GetXValue();

		var nSQL = GetProxy().SQLService();  
	  var param =  '<SOURCE oi_adelanto="'+ oi_adelanto + '" />';

		var aprobado = nSQL.GetOBJ(Ctrl("main").getResource("GetAprobado"), param);
		if (aprobado.usuario_aprobado!='-'){
			/*Ctrl('usuario_aprueba').SetXValue(aprobado.usuario_aprobado);
			Ctrl('fecha_aprobacion').SetXValue(aprobado.fecha_aprobado); */
			CtrlEnabled("APROBAR_ADELANTO",false);
		}

		var anulado = nSQL.GetOBJ(Ctrl("main").getResource("GetAnulado"), param);
		if(anulado.usuario_anula!='-'){
			/*Ctrl('usuario_anula').SetXValue(anulado.usuario_anula);
			Ctrl('fecha_anulacion').SetXValue(anulado.fecha_anulado); */
			CtrlEnabled("ANULAR_ADELANTO",false);
			CtrlEnabled("APROBAR_ADELANTO",false);		
		}
	}

}

function SAVE()
{
	if(Ctrl("n_monto_adel").GetXValue()=='0')
	{
	alert('Complete el Detalle del Adelanto');
	return false;
	}

	np = new NomadProxy("", ut);
	nSQL = np.SQLService();
	var resultReqCierre = nSQL.GetOBJ(Ctrl("main").getResource("RequiereCierre"), "<PARAM oi_tipo_adelanto=\""+Ctrl("oi_tipo_adelanto").GetXValue()+"\" />");
	if(resultReqCierre.c_req_cierre_carp == "1")
	{                                                                
		var resultEstado = nSQL.GetOBJ(Ctrl("main").getResource("EstadoCarpeta"), "<PARAM oi_carpeta=\""+Ctrl("oi_carpeta").GetXValue()+"\" />"); 

	  if(resultEstado.f_egreso == "0")
	  {
	  	alert("El tipo de adelanto seleccionado requiere que el estado de la carpeta sea CERRADO.");
	  	return false
	  }
	  else
			Ctrl('main').DoEvent("SAVE");
	}
	else
		Ctrl('main').DoEvent("SAVE");
}


function SetDescripcion()
{
	if (Ctrl('oi_carpeta').GetXValue()!='')
	{
		var oi_carpeta = Ctrl('oi_carpeta').GetXValue();
		var nSQL = GetProxy().SQLService();  
	  var param =  '<DATA oi_carpeta="'+ oi_carpeta + '" />';
		var tipoCar = nSQL.GetOBJ(Ctrl("main").getResource("getEstadoCarpeta"), param);
		if (tipoCar.c_tipo_carpeta == "2")
		{
			alert("No se pueden agregar adelantos para el tipo de carpeta 2-Acuerdo con Renuncia.");
			Ctrl('oi_carpeta').SetXValue('');
			return;
		}

		var desc = Ctrl('oi_carpeta').GetCValue().split(' - ');
		Ctrl('o_descripcion').SetXValue(desc[1]); 

		SetEmpresaDeCarpeta(); //aprovecho función ejecutada en el OnChange del control oi_carpeta
	}
}


