//guardo oi_empresa de la carpeta en control oculto para uso posterior
function SetEmpresaDeCarpeta()  
{
    var nSQL = GetProxy().SQLService();  
    var param =  '<PARAM oi_carpeta="'+ Ctrl('oi_carpeta').GetXValue() + '" />';
		var empresa = nSQL.GetOBJ(Ctrl("main").getResource("GetEmpresaDeCarpeta"), param );

		if (empresa.oi_empresa != "0")
		{
		 	 Ctrl('empresa_de_carpeta').SetXValue(empresa.oi_empresa);
    }
}

/* Botón Modificar*/
function edit_onclick()
{ 
	var id;
	if(Ctrl('main').GetMode()=='LIST')
	{
		oi_adelanto =Ctrl("LIST").GetXValue(); 
	}
	if(Ctrl('main').GetMode()=='SHOW')
	{
		oi_adelanto =Ctrl('id').GetXValue(); 
	}

	var nSQL = GetProxy().SQLService();  
	var param =  '<SOURCE oi_adelanto="'+ oi_adelanto + '" />';
	var GP = nSQL.GetOBJ(Ctrl("main").getResource("GetAdelantoTranfGP"), param);
	var aprobado = nSQL.GetOBJ(Ctrl("main").getResource("GetAprobado"), param);
	var anulado = nSQL.GetOBJ(Ctrl("main").getResource("GetAnulado"), param);

  /*if(Ctrl('main').GetMode()=='LIST')
	{	
		alert(Ctrl("LIST").GetSelectAttrValue("f_transferido"));
		if (Ctrl("LIST").GetSelectAttrValue("f_transferido")!='')
	  {
			alert('No es posible modificar el Adelanto porque ha sido transferido a GP');
	 		return false;  
	  }
	}*/ 

	if(Ctrl('main').GetMode()=='SHOW' || Ctrl('main').GetMode()=='LIST')
	{	
		if (GP.COUNT!=0){
			alert('No es posible modificar un Adelanto que ha sido transferido a GP');
			return false;
		}
		if(aprobado.usuario_aprobado!='-')
		{
			alert('No es posible modificar un Adelanto que ha sido aprobado');
			return false;
		}
		if(anulado.usuario_anula!='-')
		{
			alert('No es posible modificar un Adelanto que ha sido anulado');
			return false;
		}
	}

	return true;
}


function necesidad_fondos_onvalidate(pObj)
{
 	if (pObj.GetXValue()!='')
 	{ 	
	 	//Debe ser mayor o igual a la fecha actual
		var fechaActual = new Date();
		fechaActual = fechaActual.getFullYear()*10000 + (fechaActual.getMonth()+1)*100 + fechaActual.getDate();

		if (pObj.GetXValue() < fechaActual) 
		{
			pObj.SetError("La fecha de necesidad de fondos debe ser mayor o igual a la fecha actual.");
			return false;
		}
	}
	return true;
}


function rendirExceso_onclick()
{
	var nSQL = GetProxy().SQLService();  
  var xmlParam = new NomadXML('PARAM');
  xmlParam.SetAttr('oi_estado_ant', Ctrl('oi_estado_ant').GetXValue());
	var estado_ant = nSQL.GetOBJ(Ctrl("main").getResource("GetEstadoAdelanto"), xmlParam.ToString());


	if (Ctrl('l_habilita_exc').GetXValue()==0)
  {
		if (estado_ant.c_estado_ant == '2') //2-RENDIDO
		{
		 	 alert('No se puede marcar para rendir por exceso porque el adelanto esta 2-Rendido');
		 	 return false;
    }  
  }

  else if (Ctrl('l_habilita_exc').GetXValue()==1)
  {  	
  	if (estado_ant.c_estado_ant != '1') //1-ACTIVO
  	{
  		alert('No se puede desmarcar para rendir por exceso porque el adelanto no esta 1-Activo');
  		return false;
  	}

  	xmlParam = new NomadXML('PARAM');
  	xmlParam.SetAttr('oi_adelanto', Ctrl('id').GetXValue());
		var esta_asociado = nSQL.GetOBJ(Ctrl("main").getResource("QryAdelantoAsociado"), xmlParam.ToString());

  	if (esta_asociado.value != 0)
  	{
  		alert('No se puede desmarcar para rendir por exceso porque el adelanto esta asociado a un adelanto ya rendido');
  		return false;  	
  	}  	

  }   

  return true;

}



function pasarARendido_onclick()
{
	var nSQL = GetProxy().SQLService();  
	var xmlParam = new NomadXML('PARAM');
	xmlParam.SetAttr('oi_estado_ant', Ctrl('oi_estado_ant').GetXValue());
	var estado_ant = nSQL.GetOBJ(Ctrl("main").getResource("GetEstadoAdelanto"), xmlParam.ToString());

  if(Ctrl('oi_adelanto_exc').GetXValue()=='')
  {	
		if (estado_ant.c_estado_ant != '1') //1-ACTIVO
		{
			alert('El adelanto solo se puede marcar como rendido si esta 1-Activo');			
		}
		else
		{
			selectAdelanto();		
		}
	}
	else
	{
		if (estado_ant.c_estado_ant != '2') //2-RENDIDO
		{
			alert('El adelanto solo se puede desmarcar como rendido si esta 2-Rendido y tiene un adelanto asociado');			
		}
		else
		{
			Ctrl('main').DoEvent('DESMARCAR-RENDIDO');
		}	
	}
}


function selectAdelanto()
{
	var xmlParam = new NomadXML("CARPETA");	
	xmlParam.SetAttr("oi_carpeta",Ctrl("oi_carpeta").GetXValue());

	openNewFlow("NucleusRH.Base.Legales.Adelantos.flow", "adelanto_asociado", xmlParam.ToString(), new ObjtectResult(), "S");
}



function ObjtectResult()
{
	this.processResult = function(xmlIn)
	{
		var xmlResult;		
		xmlResult = new NomadXML(xmlIn);		

		if (xmlResult.GetAttr("oi_adelanto_exc")!="0")
		{

			Ctrl("new_oi_adelanto_exc").SetXValue(xmlResult.GetAttr("oi_adelanto_exc"));			
			Ctrl("main").DoEvent("MARCAR-RENDIDO");				
		}
	}
}      

