function ValidoAdel()
{ 
	var oi_adel;
	if(Ctrl('main').GetMode()=='LIST')
	{
		oi_adel = Ctrl('LIST').GetXValue();
	}
	if(Ctrl('main').GetMode()=='SHOW')
	{
		oi_adel = Ctrl('id').GetXValue(); 
	}
		var nSQL = GetProxy().SQLService();
		var param = '<SOURCE oi_adelanto="'+ oi_adel + '" />';

		var GP = nSQL.GetOBJ(Ctrl("main").getResource("GetAdelantoTranfGP"), param);
		var Rend  = nSQL.GetOBJ(Ctrl("main").getResource("GetRendiciones"), param);

		if (GP.COUNT != 0) //Si COUNT es distinto de vacío tiene comprobantes transferidos a GP
		{
			alert('El adelanto no se puede Eliminar si tiene comprobantes transferidos');
			return false;			
		}
		else
		{
			if(Rend.COUNT !=0)
			{
				alert('El adelanto no se puede Eliminar si tiene rendiciones cargadas');
				return false;
			}
			else
			{
				Ctrl('main').DoEvent('DELETE');	
			}
		}

}

function valido_anular_adelanto()
{ 

 	if(Ctrl('main').GetMode()=='SHOW')
	{ 
		var oi_estado_ant = Ctrl('oi_estado_ant').GetXValue();
		oi_adel = Ctrl('id').GetXValue(); 

		var nSQL = GetProxy().SQLService();  
   	var param =  '<SOURCE oi_estado_ant="'+ oi_estado_ant + '" />';
		var estado = nSQL.GetOBJ(Ctrl("main").getResource("GetEstadoAdelanto"), param);

		var parametro =  '<SOURCE oi_adelanto="'+ oi_adel + '" />';
		var GP = nSQL.GetOBJ(Ctrl("main").getResource("GetAdelantoTranfGP"), parametro);

  	if (estado.c_estado_ant=='1' && GP.COUNT != 0)
		{    
			Ctrl('main').DoEvent("ANULAR-ADELANTO");
		}
		else
		{ 
   		alert('Para anular el adelanto el estado debe ser 1-Activo y además tener comprobantes transferidos');
			return false;	
		}
	}
}

qry:select.qry:xquery:
for $r in SQL('
SELECT count(R.oi_rendicion) as REN FROM LEG06_RENDICIONES as R WHERE R.oi_adelanto = {$PARAM/@oi_adelanto}
')/ROWS/ROW
